#!/usr/bin/env python3
"""
Fixes two bugs in your custom folders feature (unrelated to the backups work):

1. "0 documents" on folder cards (Home page grid, and any subfolder listing):
   the query backing that view (getChildFolders, used by the folder-contents
   "browse" endpoint) never computed a document count at all -- it was a plain
   folder select, no join. Clicking INTO a folder worked fine because that's a
   totally different code path (it lists the folder's actual documents, not a
   count). Fixed by giving getChildFolders the same count-join logic
   getOrganizationFolders already had.

2. No way to delete/rename the folder you're currently browsing inside (only
   subfolder CARDS had that dropdown, not the folder you've navigated into).
   Added a rename/delete dropdown next to "New folder" / "Upload here" on the
   folder detail page, shown whenever you're inside a folder (not at the Home
   root). Deleting navigates you back to the parent folder (or Home).

Run from the repo root:
    python3 apply-folders-fixes.py

Full-file overwrite for the 2 files it touches -- independent of all the
backups scripts, doesn't need any of them applied first or after.
"""
import base64
from pathlib import Path

FILES = {
    "apps/papra-server/src/modules/folders/folders.repository.ts": "",
    "apps/papra-client/src/modules/folders/pages/folder.page.tsx": "",
}

def main():
    for path_str, b64_content in FILES.items():
        path = Path(path_str)
        if not path.parent.exists():
            print(f"! parent dir missing, creating: {path.parent}")
            path.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content).decode("utf-8")
        path.write_text(content)
        print(f"\u2714 wrote {path} ({len(content)} bytes)")
    print("\nDone. No migration needed. Restart pnpm dev and hard-refresh the client.")

if __name__ == "__main__":
    main()
